hema: stringPtr("analytics"), // Optional: defaults to public when omitted\n      Keys: []*keyval.StoreInput{\n          {Value: &keyval.StoreInput_RawString{RawString: "X"}},\n      },\n  })\n  if err != nil {\n      return err\n  }\n  fmt.Println(" Successfully deleted key \'X\' from store ai_store")\n  return nil\n}\n\n\nfunc main() {\n  ctx, cancel := context.WithTimeout(context.Background(), 15*time.Second)\n  defer cancel()\n\n\n  client, err := NewAIClient(ctx)\n  if err != nil {\n      log.Fatalf(" Failed to create AI client: %v", err)\n  }\n  defer client.Close()\n\n\n  if err := client.exampleDeleteKeyAI(); err != nil {\n      log.Fatalf(" DeleteKey failed: %v", err)\n  }\n}\n'})})}),(0,l.jsx)(s.A,{value:"rust",label:"Rust",children:(0,l.jsx)(n.pre,{children:(0,l.jsx)(n.code,{className:"language-rust",children:'use ahnlich_client_rs::ai::AiClient;\nuse ahnlich_client_rs::error::AhnlichError;\nuse ahnlich_types::ai::query::DelKey;\nuse ahnlich_types::ai::server::Del;\nuse ahnlich_types::keyval::StoreInput;\nuse ahnlich_types::keyval::store_input::Value;\n\n\n#[tokio::main]\nasync fn main() -> Result<(), AhnlichError> {\n    // Connect to server\n    let ai_client = AiClient::new("http://127.0.0.1:1370".to_string())\n        .await\n        .expect(" Failed to connect AI client");\n\n\n    // Define key to delete\n    let params = DelKey {\n        store: "Deven Kicks".to_string(),\n        schema: Some("analytics".to_string()),\n        keys: vec![StoreInput {\n            value: Some(Value::RawString("Nike Air Jordans".to_string())),\n        }],\n    };\n\n\n    // Call delete\n    let response: Del = ai_client.del_key(params, None).await?;\n    println!(" Deleted key result: {:?}", response);\n\n\n    Ok(())\n}\n'})})}),(0,l.jsx)(s.A,{value:"cli",label:"CLI",children:(0,l.jsx)(n.pre,{children:(0,l.jsx)(n.code,{className:"language-bash",children:"DELETEKEY ([This is a sentence]) IN my_store\n"})})})]})})]}),"\n",(0,l.jsx)(n.h2,{id:"response",children:"Res